// // This module implements a 16-bit shift register with parallel load and shift functionality.
// The register loads a 16-bit input data (data_in) when the load signal is inactive,
// and shifts its contents to the left on each negative edge of the clock signal (clk)
// when the shift signal is inactive. The register also has an active-high reset signal (rst_n)
// to reset its contents to 0.
module shift_register_16bit (
    input clk,
    input rst_n,
    input load,
    input shift,
    input [15:0] data_in,
    output reg [15:0] data_out
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        data_out <= 16'b0;
    else if (load)
        data_out <= data_in;
    else if (shift)
        data_out <= {1'b0, data_out[15:1]};
end

endmodule

